// ============================================================
// 繁簡互通
// ============================================================
function toSimplified(str) {
  if (!str || typeof T2S === "undefined") return (str || "").toLowerCase();
  return [...str].map(ch => T2S[ch] || ch).join("").toLowerCase();
}
function matchQuery(text, query) {
  if (!query) return true;
  return toSimplified(text).includes(toSimplified(query));
}

// ============================================================
// Utility
// ============================================================
function buildIndex(songs) {
  const singers = {}, composers = {}, years = {};
  songs.forEach((s, i) => {
    if (s.s) { if (!singers[s.s]) singers[s.s] = []; singers[s.s].push(i); }
    if (s.c) { if (!composers[s.c]) composers[s.c] = []; composers[s.c].push(i); }
    if (s.y) { if (!years[s.y]) years[s.y] = []; years[s.y].push(i); }
  });
  return { singers, composers, years };
}
function sortedEntries(obj) {
  return Object.entries(obj).sort((a, b) => b[1].length - a[1].length);
}

// ============================================================
// Shared Components
// ============================================================
function Tag({ label, color }) {
  return (
    <span style={{
      display: "inline-block", fontSize: 11, padding: "1px 6px",
      borderRadius: 3, background: color || C.tag, color: C.tagText,
      marginLeft: 6, verticalAlign: "middle", fontWeight: 500,
    }}>{label}</span>
  );
}

function SearchInput({ value, onChange, placeholder }) {
  return (
    <div style={{ position: "relative", marginBottom: 12 }}>
      <input type="text" value={value} onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: "100%", boxSizing: "border-box",
          padding: "10px 14px 10px 36px",
          border: `1px solid ${C.border}`, borderRadius: 8,
          background: C.white, color: C.text, fontSize: 14,
          outline: "none", fontFamily: "inherit",
        }}
      />
      <span style={{
        position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)",
        color: C.textLight, fontSize: 15, pointerEvents: "none",
      }}>⌕</span>
    </div>
  );
}

function NameList({ entries, onSelect, selected, labelSuffix = "首" }) {
  return (
    <div style={{
      maxHeight: 420, overflowY: "auto",
      border: `1px solid ${C.border}`, borderRadius: 8, background: C.white,
    }}>
      {entries.map(([name, indices]) => {
        const isActive = selected === name;
        return (
          <div key={name} onClick={() => onSelect(name)}
            style={{
              padding: "9px 14px", cursor: "pointer",
              background: isActive ? C.card : "transparent",
              borderBottom: `1px solid ${C.border}`,
              display: "flex", justifyContent: "space-between", alignItems: "center",
              transition: "background .15s",
            }}
            onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = C.cardHover; }}
            onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = "transparent"; }}
          >
            <span style={{ color: C.text, fontSize: 14 }}>{name}</span>
            <span style={{ color: C.textLight, fontSize: 12 }}>{indices.length} {labelSuffix}</span>
          </div>
        );
      })}
      {entries.length === 0 && (
        <div style={{ padding: 20, textAlign: "center", color: C.textLight, fontSize: 13 }}>無結果</div>
      )}
    </div>
  );
}

// ============================================================
// Clickable Name (link-style text for drill-down)
// ============================================================
function ClickableName({ name, onClick, color }) {
  if (!name || !onClick) return <span style={{ color: color || C.textMid }}>{name || "—"}</span>;
  return (
    <span
      onClick={(e) => { e.stopPropagation(); onClick(name); }}
      style={{
        color: C.link, cursor: "pointer",
        borderBottom: `1px dashed ${C.border}`,
        transition: "color .15s",
      }}
      onMouseEnter={e => { e.currentTarget.style.color = C.linkHover; e.currentTarget.style.borderBottomColor = C.linkHover; }}
      onMouseLeave={e => { e.currentTarget.style.color = C.link; e.currentTarget.style.borderBottomColor = C.border; }}
    >{name}</span>
  );
}

// ============================================================
// Breadcrumb
// ============================================================
function Breadcrumb({ stack, onNavigate }) {
  if (!stack || stack.length === 0) return null;
  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 4, flexWrap: "wrap",
      marginBottom: 10, fontSize: 13, color: C.textMid,
    }}>
      {stack.map((item, i) => (
        <span key={i} style={{ display: "flex", alignItems: "center", gap: 4 }}>
          {i > 0 && <span style={{ color: C.textLight }}>›</span>}
          {i < stack.length - 1 ? (
            <span
              onClick={() => onNavigate(i)}
              style={{ color: C.link, cursor: "pointer", borderBottom: `1px dashed ${C.border}` }}
            >{item.label}</span>
          ) : (
            <span style={{ color: C.text, fontWeight: 600 }}>{item.label}</span>
          )}
        </span>
      ))}
    </div>
  );
}

// ============================================================
// DrillDown Song Table (with clickable singer & composer)
// ============================================================
const thStyle = {
  padding: "8px 10px", fontWeight: 600, color: C.text, fontSize: 12,
  letterSpacing: 0.5, borderBottom: `2px solid ${C.border}`, textAlign: "center",
};
const tdStyle = { padding: "8px 10px", color: C.text };

function SongTable({ songs, data, showSinger = true, showComposer = true, showYear = true, onClickSinger, onClickComposer, onClickYear }) {
  if (!songs || songs.length === 0) {
    return <div style={{ padding: 20, color: C.textLight, fontSize: 13, textAlign: "center" }}>選擇項目查看作品</div>;
  }
  const sorted = [...songs].sort((a, b) => (data[a].y || 0) - (data[b].y || 0));
  return (
    <div style={{ maxHeight: 480, overflowY: "auto", border: `1px solid ${C.border}`, borderRadius: 8, background: C.white }}>
      <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
        <thead>
          <tr style={{ background: C.card, position: "sticky", top: 0, zIndex: 1 }}>
            {showYear && <th style={thStyle}>年份</th>}
            <th style={{ ...thStyle, textAlign: "left" }}>歌曲</th>
            {showSinger && <th style={{ ...thStyle, textAlign: "left" }}>歌手</th>}
            {showComposer && <th style={{ ...thStyle, textAlign: "left" }}>作曲</th>}
          </tr>
        </thead>
        <tbody>
          {sorted.map((idx, i) => {
            const s = data[idx];
            const src = s.r && SOURCE_LABELS[s.r];
            return (
              <tr key={i} style={{ borderBottom: `1px solid ${C.border}` }}
                onMouseEnter={e => e.currentTarget.style.background = C.cardHover}
                onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                {showYear && <td style={{ ...tdStyle, width: 50, textAlign: "center" }}>
                  {onClickYear ? <ClickableName name={String(s.y)} onClick={(v) => onClickYear(Number(v))} color={C.textMid} /> : <span style={{ color: C.textMid }}>{s.y}</span>}
                </td>}
                <td style={tdStyle}>{s.t}{src && <Tag label={src.label} color={src.color} />}</td>
                {showSinger && <td style={tdStyle}>
                  <ClickableName name={s.s} onClick={onClickSinger} color={C.textMid} />
                </td>}
                {showComposer && <td style={tdStyle}>
                  {s.c ? <ClickableName name={s.c} onClick={onClickComposer} color={C.textMid} /> : <span style={{ color: C.textLight }}>—</span>}
                </td>}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

// ============================================================
// DrillDown View (shows a person's songs with full navigation)
// ============================================================
function DrillDownView({ type, name, data, index, onClickSinger, onClickComposer, onClickYear }) {
  const songs = type === "singer" ? (index.singers[name] || [])
    : type === "composer" ? (index.composers[name] || [])
    : type === "year" ? (index.years[Number(name)] || index.years[name] || [])
    : [];
  // singer view: hide singer col, show composer+year; composer view: hide composer col; year view: hide year col
  const showSinger = type !== "singer";
  const showComposer = type !== "composer";
  const showYear = type !== "year";
  return (
    <div>
      <div style={{ marginBottom: 8, color: C.textMid, fontSize: 13 }}>
        {type === "year" ? `${name} 年：林夕該年 ${songs.length} 首作品`
          : type === "singer" ? `${name}：${songs.length} 首粵語作品`
          : `${name}：與林夕合作 ${songs.length} 首`}
      </div>
      <SongTable
        songs={songs} data={data}
        showSinger={showSinger} showComposer={showComposer} showYear={showYear}
        onClickSinger={onClickSinger} onClickComposer={onClickComposer} onClickYear={onClickYear}
      />
    </div>
  );
}

// ============================================================
// Hook: useNavStack (shared drill-down logic)
// ============================================================
function useNavStack() {
  const [stack, setStack] = useState([]);

  const push = useCallback((type, name) => {
    setStack(prev => {
      if (prev.length > 0 && prev[prev.length - 1].type === type && prev[prev.length - 1].name === name) return prev;
      const label = type === "year" ? `${name} 年` : name;
      return [...prev, { type, name, label }];
    });
  }, []);

  const navigateTo = useCallback((idx) => {
    setStack(prev => prev.slice(0, idx + 1));
  }, []);

  const clear = useCallback(() => setStack([]), []);

  const current = stack.length > 0 ? stack[stack.length - 1] : null;

  return { stack, push, navigateTo, clear, current };
}

// ============================================================
// Tab: 按歌手
// ============================================================
function TabSinger({ data, index }) {
  const [search, setSearch] = useState("");
  const [selected, setSelected] = useState(null);
  const nav = useNavStack();

  const filtered = useMemo(() => {
    const all = sortedEntries(index.singers);
    if (!search.trim()) return all;
    return all.filter(([name]) => matchQuery(name, search.trim()));
  }, [index.singers, search]);

  const songs = selected ? index.singers[selected] : null;

  const handleSelect = (name) => {
    setSelected(name);
    nav.clear();
  };

  const handleClickComposer = (name) => {
    if (index.composers[name]) {
      if (nav.stack.length === 0 && selected) {
        // Push the initial singer first, then the composer
        nav.push("singer", selected);
      }
      nav.push("composer", name);
    }
  };

  const handleClickSinger = (name) => {
    if (index.singers[name]) {
      nav.push("singer", name);
    }
  };

  const handleClickYear = (year) => {
    if (index.years[year]) {
      if (nav.stack.length === 0 && selected) {
        nav.push("singer", selected);
      }
      nav.push("year", String(year));
    }
  };

  // If nav stack is active, show drill-down view
  const showDrillDown = nav.current !== null;

  return (
    <div style={{ display: "flex", gap: 16, minHeight: 400, flexWrap: "wrap" }}>
      <div style={{ width: 260, flexShrink: 0 }}>
        <SearchInput value={search} onChange={setSearch} placeholder="搜尋歌手（繁簡皆可）…" />
        <NameList entries={filtered} onSelect={handleSelect} selected={selected} />
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        {showDrillDown ? (
          <>
            <Breadcrumb stack={nav.stack} onNavigate={(idx) => nav.navigateTo(idx)} />
            <DrillDownView
              type={nav.current.type} name={nav.current.name}
              data={data} index={index}
              onClickSinger={handleClickSinger} onClickComposer={handleClickComposer} onClickYear={handleClickYear}
            />
          </>
        ) : (
          <>
            {selected && <div style={{ marginBottom: 8, color: C.textMid, fontSize: 13 }}>{selected}：{songs.length} 首粵語作品</div>}
            <SongTable songs={songs} data={data} showSinger={false}
              onClickComposer={handleClickComposer} onClickYear={handleClickYear} />
          </>
        )}
      </div>
    </div>
  );
}

