// ============================================================
// Tab: 按年份
// ============================================================
function TabYear({ data, index }) {
  const [selected, setSelected] = useState(null);
  const nav = useNavStack();

  const yearList = useMemo(() =>
    Object.entries(index.years).map(([y, ids]) => [Number(y), ids]).sort((a, b) => b[0] - a[0]),
    [index.years]
  );
  const songs = selected !== null ? index.years[selected] : null;

  const handleSelect = (year) => { setSelected(year); nav.clear(); };

  const handleClickSinger = (name) => {
    if (index.singers[name]) {
      if (nav.stack.length === 0 && selected !== null) {
        nav.push("year", String(selected));
      }
      nav.push("singer", name);
    }
  };
  const handleClickComposer = (name) => {
    if (index.composers[name]) {
      if (nav.stack.length === 0 && selected !== null) {
        nav.push("year", String(selected));
      }
      nav.push("composer", name);
    }
  };

  const handleClickYear = (year) => {
    if (index.years[year]) {
      nav.push("year", String(year));
    }
  };

  const showDrillDown = nav.current !== null;

  return (
    <div style={{ display: "flex", gap: 16, minHeight: 400, flexWrap: "wrap" }}>
      <div style={{ width: 200, flexShrink: 0 }}>
        <div style={{ maxHeight: 480, overflowY: "auto", border: `1px solid ${C.border}`, borderRadius: 8, background: C.white }}>
          {yearList.map(([year, ids]) => {
            const isActive = selected === year;
            return (
              <div key={year} onClick={() => handleSelect(year)}
                style={{
                  padding: "9px 14px", cursor: "pointer",
                  background: isActive ? C.card : "transparent",
                  borderBottom: `1px solid ${C.border}`,
                  display: "flex", justifyContent: "space-between", alignItems: "center",
                }}
                onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = C.cardHover; }}
                onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = "transparent"; }}>
                <span style={{ color: C.text, fontSize: 14, fontWeight: 500 }}>{year}</span>
                <span style={{ color: C.textLight, fontSize: 12 }}>{ids.length} 首</span>
              </div>
            );
          })}
        </div>
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        {showDrillDown ? (
          <>
            <Breadcrumb stack={nav.stack} onNavigate={(idx) => nav.navigateTo(idx)} />
            <DrillDownView
              type={nav.current.type} name={nav.current.name}
              data={data} index={index}
              onClickSinger={handleClickSinger} onClickComposer={handleClickComposer} onClickYear={handleClickYear}
            />
          </>
        ) : (
          <>
            {selected !== null && <div style={{ marginBottom: 8, color: C.textMid, fontSize: 13 }}>{selected} 年：{songs.length} 首作品</div>}
            <SongTable songs={songs} data={data} showYear={false}
              onClickSinger={handleClickSinger} onClickComposer={handleClickComposer} />
          </>
        )}
      </div>
    </div>
  );
}

// ============================================================
// Pill Selector
// ============================================================
function PillSelector({ items, selected, onSelect, index }) {
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
      {items.map(name => {
        const isActive = selected === name;
        const count = index[name] ? index[name].length : 0;
        return (
          <button key={name} onClick={() => onSelect(isActive ? null : name)}
            style={{
              padding: "5px 12px", borderRadius: 16, border: "none",
              background: isActive ? C.pillActive : C.pillBg,
              color: isActive ? C.pillActiveText : C.text,
              fontSize: 13, cursor: "pointer", fontFamily: "inherit",
              transition: "all .15s", fontWeight: isActive ? 600 : 400,
              whiteSpace: "nowrap",
            }}>
            {name}
            <span style={{ fontSize: 11, marginLeft: 4, opacity: 0.7 }}>{count}</span>
          </button>
        );
      })}
    </div>
  );
}

function MiniTab({ active, onClick, label }) {
  return (
    <button onClick={onClick} style={{
      padding: "3px 10px", borderRadius: 12, border: `1px solid ${active ? C.accent : C.border}`,
      background: active ? C.accent : "transparent",
      color: active ? C.white : C.textMid,
      fontSize: 11, cursor: "pointer", fontFamily: "inherit", fontWeight: active ? 600 : 400,
    }}>{label}</button>
  );
}

// ============================================================
// Tab: 交叉查詢
// ============================================================
function TabCross({ data, index }) {
  const [singer, setSinger] = useState(null);
  const [composer, setComposer] = useState(null);
  const [singerQ, setSingerQ] = useState("");
  const [composerQ, setComposerQ] = useState("");
  const [singerMode, setSingerMode] = useState("hot");
  const [composerMode, setComposerMode] = useState("hot");
  const nav = useNavStack();

  const otherSingers = useMemo(() =>
    sortedEntries(index.singers).filter(([name]) => !HOT_SINGERS.includes(name)), [index.singers]);
  const otherComposers = useMemo(() =>
    sortedEntries(index.composers).filter(([name]) => !HOT_COMPOSERS.includes(name)), [index.composers]);

  const singerSearchResults = useMemo(() => {
    if (!singerQ.trim()) return otherSingers.slice(0, 30);
    return otherSingers.filter(([name]) => matchQuery(name, singerQ.trim())).slice(0, 30);
  }, [singerQ, otherSingers]);
  const composerSearchResults = useMemo(() => {
    if (!composerQ.trim()) return otherComposers.slice(0, 30);
    return otherComposers.filter(([name]) => matchQuery(name, composerQ.trim())).slice(0, 30);
  }, [composerQ, otherComposers]);

  const results = useMemo(() => {
    if (!singer && !composer) return null;
    const singerSet = singer ? new Set(index.singers[singer] || []) : null;
    const composerSet = composer ? new Set(index.composers[composer] || []) : null;
    if (singerSet && composerSet) return [...singerSet].filter(i => composerSet.has(i));
    if (singerSet) return [...singerSet];
    if (composerSet) return [...composerSet];
    return null;
  }, [singer, composer, index]);

  const selectSinger = (name) => { setSinger(name === singer ? null : name); setSingerQ(name || ""); nav.clear(); };
  const selectComposer = (name) => { setComposer(name === composer ? null : name); setComposerQ(name || ""); nav.clear(); };
  const clearSinger = () => { setSinger(null); setSingerQ(""); nav.clear(); };
  const clearComposer = () => { setComposer(null); setComposerQ(""); nav.clear(); };

  const handleClickSinger = (name) => {
    if (index.singers[name]) {
      if (nav.stack.length === 0) {
        const lbl = singer && composer ? `${singer} × ${composer}` : singer || composer || "";
        if (lbl) nav.push("cross", lbl);
      }
      nav.push("singer", name);
    }
  };
  const handleClickComposer = (name) => {
    if (index.composers[name]) {
      if (nav.stack.length === 0) {
        const lbl = singer && composer ? `${singer} × ${composer}` : singer || composer || "";
        if (lbl) nav.push("cross", lbl);
      }
      nav.push("composer", name);
    }
  };
  const handleClickYear = (year) => {
    if (index.years[year]) {
      if (nav.stack.length === 0) {
        const lbl = singer && composer ? `${singer} × ${composer}` : singer || composer || "";
        if (lbl) nav.push("cross", lbl);
      }
      nav.push("year", String(year));
    }
  };

  const showDrillDown = nav.current !== null;

  return (
    <div>
      {/* Singer selection */}
      <div style={{ marginBottom: 16 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, flexWrap: "wrap" }}>
          <span style={{ fontSize: 13, color: C.textMid, fontWeight: 600 }}>歌手</span>
          <div style={{ display: "flex", gap: 4 }}>
            <MiniTab active={singerMode === "hot"} onClick={() => setSingerMode("hot")} label="常見歌手" />
            <MiniTab active={singerMode === "search"} onClick={() => setSingerMode("search")} label="其他歌手" />
          </div>
          {singer && (
            <span style={{ marginLeft: "auto", fontSize: 12, color: C.accent, cursor: "pointer", display: "flex", alignItems: "center", gap: 4 }} onClick={clearSinger}>
              已選：<strong>{singer}</strong> ✕
            </span>
          )}
        </div>
        {singerMode === "hot" ? (
          <PillSelector items={HOT_SINGERS} selected={singer} onSelect={selectSinger} index={index.singers} />
        ) : (
          <div style={{ position: "relative" }}>
            <SearchInput value={singerQ} onChange={(v) => { setSingerQ(v); if (singer) setSinger(null); nav.clear(); }} placeholder="搜尋其他歌手（繁簡皆可）…" />
            {!singer && singerQ.trim() && singerSearchResults.length > 0 && (
              <div style={{ border: `1px solid ${C.border}`, borderRadius: 8, background: C.white, maxHeight: 180, overflowY: "auto" }}>
                {singerSearchResults.map(([name, ids]) => (
                  <div key={name} onClick={() => selectSinger(name)}
                    style={{ padding: "7px 12px", cursor: "pointer", fontSize: 13, display: "flex", justifyContent: "space-between", borderBottom: `1px solid ${C.border}` }}
                    onMouseEnter={e => e.currentTarget.style.background = C.cardHover}
                    onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                    <span>{name}</span><span style={{ color: C.textLight }}>{ids.length}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Composer selection */}
      <div style={{ marginBottom: 16 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, flexWrap: "wrap" }}>
          <span style={{ fontSize: 13, color: C.textMid, fontWeight: 600 }}>作曲人</span>
          <div style={{ display: "flex", gap: 4 }}>
            <MiniTab active={composerMode === "hot"} onClick={() => setComposerMode("hot")} label="常見作曲" />
            <MiniTab active={composerMode === "search"} onClick={() => setComposerMode("search")} label="其他作曲" />
          </div>
          {composer && (
            <span style={{ marginLeft: "auto", fontSize: 12, color: C.accent, cursor: "pointer", display: "flex", alignItems: "center", gap: 4 }} onClick={clearComposer}>
              已選：<strong>{composer}</strong> ✕
            </span>
          )}
        </div>
        {composerMode === "hot" ? (
          <PillSelector items={HOT_COMPOSERS} selected={composer} onSelect={selectComposer} index={index.composers} />
        ) : (
          <div style={{ position: "relative" }}>
            <SearchInput value={composerQ} onChange={(v) => { setComposerQ(v); if (composer) setComposer(null); nav.clear(); }} placeholder="搜尋其他作曲人（繁簡皆可）…" />
            {!composer && composerQ.trim() && composerSearchResults.length > 0 && (
              <div style={{ border: `1px solid ${C.border}`, borderRadius: 8, background: C.white, maxHeight: 180, overflowY: "auto" }}>
                {composerSearchResults.map(([name, ids]) => (
                  <div key={name} onClick={() => selectComposer(name)}
                    style={{ padding: "7px 12px", cursor: "pointer", fontSize: 13, display: "flex", justifyContent: "space-between", borderBottom: `1px solid ${C.border}` }}
                    onMouseEnter={e => e.currentTarget.style.background = C.cardHover}
                    onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                    <span>{name}</span><span style={{ color: C.textLight }}>{ids.length}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Results */}
      {showDrillDown ? (
        <>
          <Breadcrumb stack={nav.stack} onNavigate={(idx) => nav.navigateTo(idx)} />
          <DrillDownView
            type={nav.current.type} name={nav.current.name}
            data={data} index={index}
            onClickSinger={handleClickSinger} onClickComposer={handleClickComposer} onClickYear={handleClickYear}
          />
        </>
      ) : (
        <>
          {results && (
            <div style={{ marginBottom: 8, color: C.textMid, fontSize: 13 }}>
              {singer && composer ? `${singer} × ${composer}：${results.length} 首合作`
                : singer ? `${singer}：${results.length} 首` : `${composer}：${results.length} 首`}
            </div>
          )}
          <SongTable songs={results} data={data}
            onClickSinger={handleClickSinger} onClickComposer={handleClickComposer} onClickYear={handleClickYear} />
        </>
      )}
    </div>
  );
}

// ============================================================
// Tab: 統計
// ============================================================
function TabStats({ data, index }) {
  const topSingers = useMemo(() => sortedEntries(index.singers).slice(0, 20), [index.singers]);
  const topComposers = useMemo(() => sortedEntries(index.composers).slice(0, 20), [index.composers]);
  const yearData = useMemo(() =>
    Object.entries(index.years).map(([y, ids]) => ({ year: Number(y), count: ids.length })).sort((a, b) => a.year - b.year),
    [index.years]
  );
  const maxYear = Math.max(...yearData.map(d => d.count));
  const sourceStats = useMemo(() => {
    const counts = {};
    data.forEach(s => { if (s.r) counts[s.r] = (counts[s.r] || 0) + 1; });
    return Object.entries(counts).sort((a, b) => b[1] - a[1]);
  }, [data]);

  return (
    <div>
      <div style={{ marginBottom: 28 }}>
        <h3 style={sectionTitle}>年度產量</h3>
        <div style={{ overflowX: "auto" }}>
          <div style={{ display: "flex", alignItems: "flex-end", gap: 2, height: 140, padding: "0 4px", minWidth: yearData.length * 18 }}>
            {yearData.map(d => (
              <div key={d.year} style={{ display: "flex", flexDirection: "column", alignItems: "center", flex: "0 0 auto", width: 16 }}>
                <div style={{ width: 12, height: Math.max(2, (d.count / maxYear) * 110), background: C.accent, borderRadius: "3px 3px 0 0" }} title={`${d.year}: ${d.count} 首`} />
                <div style={{ fontSize: 9, color: C.textLight, marginTop: 3, transform: "rotate(-60deg)", transformOrigin: "top center", whiteSpace: "nowrap" }}>
                  {d.year % 5 === 0 ? d.year : ""}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div style={{ display: "flex", gap: 24, flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: 280 }}>
          <h3 style={sectionTitle}>歌手 Top 20</h3>
          <div style={{ border: `1px solid ${C.border}`, borderRadius: 8, background: C.white }}>
            {topSingers.map(([name, ids], i) => (
              <div key={name} style={{ display: "flex", alignItems: "center", gap: 10, padding: "6px 12px", borderBottom: `1px solid ${C.border}` }}>
                <span style={{ color: C.textLight, fontSize: 11, width: 20, textAlign: "right" }}>{i + 1}</span>
                <span style={{ flex: 1, fontSize: 13, color: C.text }}>{name}</span>
                <div style={{ width: Math.max(4, (ids.length / topSingers[0][1].length) * 120), height: 8, background: C.pink, borderRadius: 4 }} />
                <span style={{ fontSize: 12, color: C.textMid, width: 30, textAlign: "right" }}>{ids.length}</span>
              </div>
            ))}
          </div>
        </div>
        <div style={{ flex: 1, minWidth: 280 }}>
          <h3 style={sectionTitle}>作曲人 Top 20</h3>
          <div style={{ border: `1px solid ${C.border}`, borderRadius: 8, background: C.white }}>
            {topComposers.map(([name, ids], i) => (
              <div key={name} style={{ display: "flex", alignItems: "center", gap: 10, padding: "6px 12px", borderBottom: `1px solid ${C.border}` }}>
                <span style={{ color: C.textLight, fontSize: 11, width: 20, textAlign: "right" }}>{i + 1}</span>
                <span style={{ flex: 1, fontSize: 13, color: C.text }}>{name}</span>
                <div style={{ width: Math.max(4, (ids.length / topComposers[0][1].length) * 120), height: 8, background: C.blue, borderRadius: 4 }} />
                <span style={{ fontSize: 12, color: C.textMid, width: 30, textAlign: "right" }}>{ids.length}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {sourceStats.length > 0 && (
        <div style={{ marginTop: 24 }}>
          <h3 style={sectionTitle}>外國作曲來源</h3>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            {sourceStats.map(([key, count]) => {
              const info = SOURCE_LABELS[key] || { label: key, color: C.tag };
              return (
                <div key={key} style={{ padding: "10px 16px", borderRadius: 8, background: info.color, color: C.tagText, fontSize: 13, textAlign: "center", minWidth: 80 }}>
                  <div style={{ fontSize: 20, fontWeight: 600, marginBottom: 2 }}>{count}</div>
                  <div>{info.label}</div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div style={{ marginTop: 24, padding: 16, background: C.card, borderRadius: 8, fontSize: 12, color: C.textMid, lineHeight: 1.6 }}>
        數據覆蓋 1985–2026 年，共 {data.length} 首粵語作品 · {Object.keys(index.singers).length} 位歌手 · {Object.keys(index.composers).length} 組作曲 credits
      </div>
    </div>
  );
}

const sectionTitle = {
  fontSize: 14, fontWeight: 600, color: C.text, marginBottom: 10,
  paddingBottom: 6, borderBottom: `1px solid ${C.border}`,
};

// ============================================================
// Global Search
// ============================================================
function GlobalSearch({ data }) {
  const [q, setQ] = useState("");
  const [open, setOpen] = useState(false);
  const results = useMemo(() => {
    if (!q.trim()) return [];
    return data.map((s, i) => ({ ...s, i }))
      .filter(s => matchQuery(s.t, q.trim()) || matchQuery(s.s, q.trim()) || matchQuery(s.c, q.trim()))
      .slice(0, 30);
  }, [q, data]);

  return (
    <div style={{ position: "relative", marginBottom: 16 }}>
      <SearchInput value={q} onChange={(v) => { setQ(v); setOpen(true); }} placeholder="搜尋歌名 / 歌手 / 作曲人（繁簡皆可）…" />
      {open && results.length > 0 && (
        <div style={{
          position: "absolute", top: "100%", left: 0, right: 0, zIndex: 20,
          background: C.white, border: `1px solid ${C.border}`, borderRadius: 8,
          boxShadow: `0 8px 24px ${C.shadow}`, maxHeight: 300, overflowY: "auto",
        }}>
          {results.map(s => (
            <div key={s.i} onClick={() => setOpen(false)}
              style={{ padding: "8px 14px", borderBottom: `1px solid ${C.border}`, cursor: "default", fontSize: 13 }}
              onMouseEnter={e => e.currentTarget.style.background = C.cardHover}
              onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
              <div style={{ color: C.text, fontWeight: 500 }}>{s.t}</div>
              <div style={{ color: C.textMid, fontSize: 12, marginTop: 2 }}>
                {s.s} · {s.y}{s.c ? ` · 曲：${s.c}` : ""}
                {s.r && SOURCE_LABELS[s.r] && <Tag label={SOURCE_LABELS[s.r].label} color={SOURCE_LABELS[s.r].color} />}
              </div>
            </div>
          ))}
        </div>
      )}
      {open && q.trim() && results.length === 0 && (
        <div style={{
          position: "absolute", top: "100%", left: 0, right: 0, zIndex: 20,
          background: C.white, border: `1px solid ${C.border}`, borderRadius: 8,
          padding: 16, textAlign: "center", color: C.textLight, fontSize: 13,
        }}>無相關結果</div>
      )}
    </div>
  );
}

