// ============================================================
const GUIDE_SECTIONS = [
  { icon: "⌕", title: "全局搜索", desc: "頂部搜索框可按歌名、歌手、作曲人搜索，支持簡體輸入匹配繁體數據" },
  { icon: "🎤", title: "按歌手", desc: "左側選擇歌手，右側顯示該歌手所有粵語作品及作曲 credits" },
  { icon: "🎹", title: "按作曲", desc: "選擇作曲人，查看其與林夕合作的全部歌曲" },
  { icon: "📅", title: "按年份", desc: "按年份瀏覽，查看林夕每年的創作產量和合作對象" },
  { icon: "🔀", title: "交叉查詢", desc: "同時選擇歌手和作曲人，查看特定搭檔的合作歌曲。常見人名可直接點選，其他可搜索" },
  { icon: "📊", title: "統計", desc: "歌手 / 作曲人排行、年度產量圖表、外國作曲來源分佈" },
  { icon: "🔗", title: "交叉導航", desc: "歌曲列表中的歌手名、作曲人名、年份均可點擊，跳轉查看該人或該年的全部作品，面包屑路徑可隨時回退" },
];

function GuideModal({ onClose }) {
  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 1000,
      background: "rgba(74,70,64,0.5)", backdropFilter: "blur(4px)",
      display: "flex", alignItems: "center", justifyContent: "center",
      padding: 20,
    }} onClick={onClose}>
      <div style={{
        background: C.bg, borderRadius: 16, maxWidth: 480, width: "100%",
        maxHeight: "85vh", overflowY: "auto",
        boxShadow: "0 20px 60px rgba(74,70,64,0.3)",
        padding: 0,
      }} onClick={e => e.stopPropagation()}>
        {/* Splash image */}
        <div style={{
          width: "100%", borderRadius: "16px 16px 0 0", overflow: "hidden",
          background: "#e8e2d8",
        }}>
          <img src={SPLASH_IMG} alt="林夕" style={{
            width: "100%", display: "block",
            objectFit: "cover", maxHeight: 320,
          }} />
        </div>

        {/* Title */}
        <div style={{ padding: "20px 24px 8px" }}>
          <h2 style={{ fontSize: 20, fontWeight: 700, color: C.text, margin: 0 }}>
            林夕粵語填詞作品
          </h2>
          <div style={{ fontSize: 13, color: C.textMid, marginTop: 4 }}>
            2764 首 · 1985–2026 · Credits 查詢
          </div>
        </div>

        {/* Guide items */}
        <div style={{ padding: "8px 24px 16px" }}>
          {GUIDE_SECTIONS.map((s, i) => (
            <div key={i} style={{
              display: "flex", gap: 12, alignItems: "flex-start",
              padding: "10px 0",
              borderBottom: i < GUIDE_SECTIONS.length - 1 ? `1px solid ${C.border}` : "none",
            }}>
              <span style={{ fontSize: 18, flexShrink: 0, width: 28, textAlign: "center" }}>{s.icon}</span>
              <div>
                <div style={{ fontSize: 14, fontWeight: 600, color: C.text, marginBottom: 2 }}>{s.title}</div>
                <div style={{ fontSize: 12, color: C.textMid, lineHeight: 1.5 }}>{s.desc}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Close button */}
        <div style={{ padding: "8px 24px 20px", textAlign: "center" }}>
          <button onClick={onClose} style={{
            padding: "10px 40px", borderRadius: 20, border: "none",
            background: C.accent, color: C.white, fontSize: 14,
            fontWeight: 600, cursor: "pointer", fontFamily: "inherit",
          }}>開始使用</button>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// App
// ============================================================
const GUIDE_SEEN_KEY = "linxi-guide-seen";

export default function App() {
  const [tab, setTab] = useState("singer");
  const data = useMemo(() => DATA, []);
  const index = useMemo(() => buildIndex(data), [data]);

  // Guide modal: show on first visit, remember dismissal
  const [showGuide, setShowGuide] = useState(() => {
    try { return !localStorage.getItem(GUIDE_SEEN_KEY); } catch(e) { return true; }
  });

  const closeGuide = useCallback(() => {
    setShowGuide(false);
    try { localStorage.setItem(GUIDE_SEEN_KEY, "1"); } catch(e) {}
  }, []);

  const openGuide = useCallback(() => setShowGuide(true), []);

  if (data.length === 0) return <div style={{ padding: 40, textAlign: "center", color: C.textMid }}>載入中…</div>;

  return (
    <div style={{
      maxWidth: 960, margin: "0 auto", padding: "24px 20px",
      fontFamily: "'Noto Sans SC', 'PingFang SC', 'Hiragino Sans GB', -apple-system, sans-serif",
      color: C.text, background: C.bg, minHeight: "100vh",
    }}>
      {/* Header with guide button */}
      <div style={{ marginBottom: 20, display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
        <div>
          <h1 style={{ fontSize: 22, fontWeight: 700, color: C.text, margin: 0, letterSpacing: 1 }}>林夕粵語填詞作品</h1>
          <div style={{ fontSize: 12, color: C.textLight, marginTop: 4 }}>{data.length} 首 · 1985–2026 · Credits 查詢</div>
        </div>
        <button onClick={openGuide} title="使用指南" style={{
          background: "none", border: `1px solid ${C.border}`, borderRadius: 8,
          padding: "6px 10px", cursor: "pointer", color: C.textMid, fontSize: 13,
          fontFamily: "inherit", display: "flex", alignItems: "center", gap: 4,
          transition: "all .15s",
        }}
          onMouseEnter={e => { e.currentTarget.style.borderColor = C.accent; e.currentTarget.style.color = C.text; }}
          onMouseLeave={e => { e.currentTarget.style.borderColor = C.border; e.currentTarget.style.color = C.textMid; }}
        >
          <span style={{ fontSize: 15 }}>?</span>
          <span>指南</span>
        </button>
      </div>

      <GlobalSearch data={data} />

      <div style={{ display: "flex", gap: 0, borderBottom: `2px solid ${C.border}`, marginBottom: 20, overflowX: "auto" }}>
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            style={{
              padding: "10px 18px", background: "none", border: "none",
              borderBottom: tab === t.id ? `2px solid ${C.accent}` : "2px solid transparent",
              marginBottom: -2, color: tab === t.id ? C.text : C.textLight,
              fontWeight: tab === t.id ? 600 : 400, fontSize: 14,
              cursor: "pointer", fontFamily: "inherit", transition: "all .15s", whiteSpace: "nowrap",
            }}>{t.label}</button>
        ))}
      </div>

      {tab === "singer" && <TabSinger data={data} index={index} />}
      {tab === "composer" && <TabComposer data={data} index={index} />}
      {tab === "year" && <TabYear data={data} index={index} />}
      {tab === "cross" && <TabCross data={data} index={index} />}
      {tab === "stats" && <TabStats data={data} index={index} />}

      {/* Guide modal */}
      {showGuide && <GuideModal onClose={closeGuide} />}
    </div>
  );
}
